1	/**
2	 * 3D viewport materials & lighting — spec §15.5.
3	 *
4	 * Centralised material + light spec resolved from CSS tokens. Token names
5	 * come from `@bim-ai/design-tokens/tokens-drafting.css` so a theme switch
6	 * triggers a deterministic rebuild from the live `:root` computed style.
7	 *
8	 * Three.js material/light objects are constructed inside Viewport.tsx —
9	 * this module returns plain JSON so it can be unit-tested without a
10	 * renderer (jsdom has no WebGL).
11	 */
12	
13	export type ElementCategoryToken =
14	  | 'wall'
15	  | 'floor'
16	  | 'roof'
17	  | 'door'
18	  | 'window'
19	  | 'stair'
20	  | 'railing'
21	  | 'room'
22	  | 'site'
23	  | 'section'
24	  | 'sheet';
25	
26	export interface CategoryMaterialSpec {
27	  category: ElementCategoryToken;
28	  /** CSS color string sourced from the corresponding `--cat-*` token. */
29	  color: string;
30	  roughness: number;
31	  metalness: number;
32	  /** Ambient occlusion strength baked into the material. */
33	  aoIntensity: number;
34	}
35	
36	export interface LightingSpec {
37	  /** DirectionalLight aligned to project north. */
38	  sun: {
39	    intensity: number;
40	    azimuthDeg: number;
41	    elevationDeg: number;
42	    /** sRGB hex string. */
43	    color: string;
44	    shadowMapSize: number;
45	  };
46	  /** Hemisphere light split between sky and ground. */
47	  hemi: {
48	    intensity: number;
49	    skyColor: string;
50	    groundColor: string;
51	  };
52	  ssao: {
53	    kernelRadius: number;
54	    minDistance: number;
55	    maxDistance: number;
56	  };
57	}
58	
59	export interface SelectionSpec {
60	  /** Edge color used for the selected element overlay (`--color-accent`). */
61	  selectedColor: string;
62	  selectedLineWidth: number;
63	  /** Edge color for the hover halo (`--draft-hover`). */
64	  hoverColor: string;
65	  hoverLineWidth: number;
66	}
67	
68	const CATEGORY_TOKEN: Record<ElementCategoryToken, string> = {
69	  wall: '--cat-wall',
70	  floor: '--cat-floor',
71	  roof: '--cat-roof',
72	  door: '--cat-door',
73	  window: '--cat-window',
74	  stair: '--cat-stair',
75	  railing: '--cat-railing',
76	  room: '--cat-room',
77	  site: '--cat-site',
78	  section: '--cat-section',
79	  sheet: '--cat-sheet',
80	};
81	
82	const FALLBACK_CATEGORY_COLOR: Record<ElementCategoryToken, string> = {
83	  wall: 'hsl(220 6% 60%)',
84	  floor: 'hsl(36 18% 70%)',
85	  roof: 'hsl(0 18% 40%)',
86	  door: 'hsl(28 30% 45%)',
87	  window: 'hsl(213 60% 70%)',
88	  stair: 'hsl(220 6% 35%)',
89	  railing: 'hsl(220 6% 28%)',
90	  room: 'hsl(150 24% 86%)',
91	  site: 'hsl(80 20% 80%)',
92	  section: 'hsl(0 70% 50%)',
93	  sheet: 'hsl(220 6% 80%)',
94	};
95	
96	export interface TokenReader {
97	  /** Read a CSS custom property from the live document. */
98	  read(token: string): string | null;
99	}
100	
101	/** Default reader: pulls from `document.documentElement` computed style.
102	 * Tests inject a fake reader. */
103	export function liveTokenReader(): TokenReader {
104	  return {
105	    read(token: string): string | null {
106	      if (typeof document === 'undefined') return null;
107	      try {
108	        const value = getComputedStyle(document.documentElement).getPropertyValue(token).trim();
109	        return value || null;
110	      } catch {
111	        return null;
112	      }
113	    },
114	  };
115	}
116	
117	export interface ResolveOptions {
118	  reader?: TokenReader;
119	  /** Override the spec'd PBR defaults (used by tests). */
120	  roughness?: number;
121	  metalness?: number;
122	  aoIntensity?: number;
123	}
124	
125	const DEFAULT_PBR = { roughness: 0.85, metalness: 0, aoIntensity: 0.4 } as const;
126	
127	/** Resolve a category material spec from the live tokens.
