  const boardProtrude = 0.012;            // 12 mm proud of wall face
  const boardH        = wallHeightM - 0.05;
  const boardD        = pitchM - 0.002;   // slight gap between boards

  const boardColor = readToken('--cat-wall', '#9ca3af');
  const boardMat = new THREE.MeshStandardMaterial({
    color: boardColor,
    roughness: 0.85,
    metalness: 0,
  });
  const boardGeom = new THREE.BoxGeometry(boardProtrude, boardH, boardD);

  for (let i = 0; i < count; i++) {
    const board = new THREE.Mesh(boardGeom, boardMat);
    board.position.set(
      -wallLenM / 2 + (i + 0.5) * pitchM,  // along wall length (local X)
      0,                                     // vertically centred (local Y)
      wallThickM / 2 + boardProtrude / 2,   // proud of front face (local Z)
    );
    board.castShadow = board.receiveShadow = true;
    addEdges(board);
    mesh.add(board);
  }
}

