function resolveDoorParams(
  door: DoorElem,
  typeEl: Extract<Element, { kind: 'family_type' }> | undefined,
  familyId: string,
): Record<string, unknown> {
  const familyDef = BUILT_IN_FAMILIES_BY_ID.get(familyId);
  const typeParams = typeEl?.parameters;
  const inst = door.overrideParams;
  return {
    widthMm:         resolveParam('widthMm', inst, typeParams, familyDef, door.widthMm),
    heightMm:        resolveParam('heightMm', inst, typeParams, familyDef, 2100),
    frameProfileMm:  resolveParam('frameProfileMm', inst, typeParams, familyDef, 70),
    wallThickMm:     resolveParam('wallThickMm', inst, typeParams, familyDef,
                       200 /* wall.thicknessMm not available here; caller patches */),
    materialKey:     resolveParam('materialKey', inst, typeParams, familyDef,
                       door.materialKey ?? 'timber'),
  };
}

function resolveWindowParams(
  win: WindowElem,
  typeEl: Extract<Element, { kind: 'family_type' }> | undefined,
  familyId: string,
): Record<string, unknown> {
  const familyDef = BUILT_IN_FAMILIES_BY_ID.get(familyId);
  const typeParams = typeEl?.parameters;
  const inst = win.overrideParams;
  return {
    widthMm:        resolveParam('widthMm', inst, typeParams, familyDef, win.widthMm),
    heightMm:       resolveParam('heightMm', inst, typeParams, familyDef, win.heightMm),
    frameProfileMm: resolveParam('frameProfileMm', inst, typeParams, familyDef, 60),
    wallThickMm:    resolveParam('wallThickMm', inst, typeParams, familyDef, 200),
    sillHeightMm:   resolveParam('sillHeightMm', inst, typeParams, familyDef, win.sillHeightMm),
  };
}

