  addEdges(jambL);
  frameGroup.add(jambL);

  const jambR = new THREE.Mesh(new THREE.BoxGeometry(frameSect, outerH, depth), frameMat);
  jambR.position.set(outerW / 2 - frameSect / 2, 0, 0);
