function lengthParam(
  key: string,
  label: string,
  defaultMm: number,
  opts: { min?: number; max?: number; instanceOverridable: boolean },
): FamilyParamDef {
  return { key, label, type: 'length_mm', default: defaultMm, ...opts };
}

