1	import {
2	  type CSSProperties,
3	  type JSX,
4	  type KeyboardEvent,
5	  useCallback,
6	  useRef,
7	  useState,
8	} from 'react';
9	import {
10	  alignmentForPick,
11	  type ViewCubeAlignment,
12	  type ViewCubeCorner,
13	  type ViewCubeFace,
14	  type ViewCubePick,
15	} from './viewCubeAlignment';
16	
17	/**
18	 * ViewCube widget — spec §15.4.
19	 *
20	 * 96 × 96 px CSS-3D cube sitting top-right of the 3D canvas. Faces +
21	 * top corners are clickable (snap camera to that alignment). The cube
22	 * also supports drag-to-orbit: dragging anywhere on the stage orbits
23	 * the main camera live via the `onDrag` callback.
24	 *
25	 * The cube tracks the camera's full pose (azimuth + elevation) rather
26	 * than only azimuth, so it mirrors the scene orientation exactly.
27	 */
28	
29	export interface ViewCubeProps {
30	  currentAzimuth: number;
31	  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
32	  currentElevation: number;
33	  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
34	  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
35	  onDrag?: (dxPx: number, dyPx: number) => void;
36	  /** Optional className for positioning. */
37	  className?: string;
38	}
39	
40	const CUBE_SIZE_PX = 68;
41	const HALF = CUBE_SIZE_PX / 2;
42	const DRAG_THRESHOLD_PX = 4;
43	
44	const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
45	  { id: 'TOP-NW', left: '6%', top: '6%' },
46	  { id: 'TOP-NE', left: '94%', top: '6%' },
47	  { id: 'TOP-SW', left: '6%', top: '94%' },
48	  { id: 'TOP-SE', left: '94%', top: '94%' },
49	];
50	
51	interface FaceDef {
52	  id: ViewCubeFace;
53	  label: string;
54	  transform: string;
55	  /** Fraction of --color-foreground mixed into --color-surface (0–1). */
56	  shade: number;
57	}
58	
59	const FACES: FaceDef[] = [
60	  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)`, shade: 0.04 },
61	  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)`, shade: 0.12 },
62	  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)`, shade: 0.08 },
63	  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)`, shade: 0.08 },
64	  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)`, shade: 0.0 },
65	  {
66	    id: 'BOTTOM',
67	    label: 'BTM',
68	    transform: `rotateX(-90deg) translateZ(${HALF}px)`,
69	    shade: 0.22,
70	  },
71	];
72	
73	export function ViewCube({
74	  currentAzimuth,
75	  currentElevation,
76	  onPick,
77	  onDrag,
78	  className,
79	}: ViewCubeProps): JSX.Element {
80	  const dragRef = useRef({ dragging: false, totalMoved: 0 });
81	  const suppressNextClickRef = useRef(false);
82	  const [isDragging, setIsDragging] = useState(false);
83	
84	  function emit(pick: ViewCubePick): void {
85	    onPick(pick, alignmentForPick(pick));
86	  }
87	
88	  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
89	    if (event.key === 'Enter' || event.key === ' ') {
90	      event.preventDefault();
91	      emit({ kind: 'home' });
92	    }
93	  }
94	
95	  const handlePointerDown = useCallback(
96	    (e: React.PointerEvent<HTMLDivElement>) => {
97	      if (e.button !== 0) return;
98	      dragRef.current = { dragging: true, totalMoved: 0 };
99	      setIsDragging(true);
100	      document.body.style.cursor = 'grabbing';
101	
102	      const onMove = (ev: PointerEvent) => {
103	        const dx = ev.movementX;
104	        const dy = ev.movementY;
105	        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
106	        onDrag?.(dx, dy);
107	      };
108	
109	      const onUp = () => {
110	        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
111	          suppressNextClickRef.current = true;
112	        }
113	        dragRef.current.dragging = false;
114	        setIsDragging(false);
115	        document.body.style.cursor = '';
116	        window.removeEventListener('pointermove', onMove);
117	        window.removeEventListener('pointerup', onUp);
118	      };
119	
120	      window.addEventListener('pointermove', onMove);
121	      window.addEventListener('pointerup', onUp);
122	    },
123	    [onDrag],
124	  );
125	
126	  const handleClickCapture = useCallback((e: React.MouseEvent) => {
127	    if (suppressNextClickRef.current) {
128	      e.stopPropagation();
129	      suppressNextClickRef.current = false;
130	    }
131	  }, []);
132	
