39	function fmtMm(value: number | null | undefined): string {
40	  if (value == null || !Number.isFinite(value)) return '—';
41	  if (Math.abs(value) >= 1000) return `${(value / 1000).toFixed(2)} m`;
42	  return `${value.toFixed(0)} mm`;
43	}
