1	import {
2	  type CSSProperties,
3	  type JSX,
4	  type KeyboardEvent,
5	  type ReactNode,
6	  useCallback,
7	  useEffect,
8	  useMemo,
9	  useRef,
10	  useState,
11	} from 'react';
12	import { useTranslation } from 'react-i18next';
13	import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';
14	
15	/**
16	 * LeftRail / Project Browser — spec §12.
17	 *
18	 * - Sticky header with a search field that filters every row by label / id.
19	 * - Vertically stacked sections (PROJECT / VIEWS / SHEETS / SCHEDULES /
20	 *   FAMILIES / EVIDENCE) with uppercase eyebrow labels.
21	 * - `role="tree"` semantics; each row is a `treeitem` with `aria-expanded`
22	 *   when it has children. Disclosure triangle is a lucide chevron.
23	 * - Keyboard: `ArrowDown`/`ArrowUp` move focus row-to-row; `ArrowRight`
24	 *   expands a closed parent or moves into its first child; `ArrowLeft`
25	 *   collapses an open parent or moves to its parent. `Enter` activates
26	 *   the focused row. `F2` invokes `onRename(rowId)`.
27	 *
28	 * Caller owns activeRowId, expansion state by default (uncontrolled), and
29	 * drag-drop reorder. The collapsed (icon-strip) variant is exposed as
30	 * `<LeftRailCollapsed/>` so AppShell can swap on `[`.
31	 */
32	
33	export type LeftRailSection = {
34	  id: string;
35	  label: string;
36	  icon?: LucideLikeIcon;
37	  rows: LeftRailRow[];
38	};
39	
40	export type LeftRailRow = {
41	  id: string;
42	  label: string;
43	  /** Lucide icon component to render at 12 px. Optional. */
44	  icon?: LucideLikeIcon;
45	  /** Subrows if any — drives the disclosure triangle and `aria-expanded`. */
46	  children?: LeftRailRow[];
47	  /** Optional secondary line shown after the label (muted). */
48	  hint?: string;
49	};
50	
51	export interface LeftRailProps {
52	  sections: LeftRailSection[];
53	  activeRowId?: string;
54	  onRowActivate?: (id: string) => void;
55	  onRowRename?: (id: string) => void;
56	  /** Initial expanded set; uncontrolled. */
57	  defaultExpanded?: ReadonlySet<string>;
58	  /** Optional hook for context-menu invocation (right-click). */
59	  onRowContextMenu?: (id: string, event: { x: number; y: number }) => void;
60	}
61	
62	/** Flatten sections + rows into a focusable order list. */
63	function flatten(
64	  sections: LeftRailSection[],
65	  expanded: ReadonlySet<string>,
66	): { id: string; depth: number; row: LeftRailRow; sectionId: string }[] {
67	  const out: { id: string; depth: number; row: LeftRailRow; sectionId: string }[] = [];
68	  function visit(rows: LeftRailRow[], depth: number, sectionId: string): void {
69	    for (const r of rows) {
70	      out.push({ id: r.id, depth, row: r, sectionId });
71	      if (r.children && r.children.length && expanded.has(r.id)) {
72	        visit(r.children, depth + 1, sectionId);
73	      }
74	    }
75	  }
76	  for (const s of sections) visit(s.rows, 0, s.id);
77	  return out;
78	}
79	
80	function matchesQuery(row: LeftRailRow, q: string): boolean {
81	  if (!q) return true;
82	  const needle = q.toLowerCase();
83	  if (row.label.toLowerCase().includes(needle)) return true;
84	  if (row.id.toLowerCase().includes(needle)) return true;
85	  if (row.hint?.toLowerCase().includes(needle)) return true;
86	  if (row.children) return row.children.some((c) => matchesQuery(c, q));
87	  return false;
88	}
89	
90	function filterRows(rows: LeftRailRow[], q: string): LeftRailRow[] {
91	  if (!q) return rows;
92	  const out: LeftRailRow[] = [];
93	  for (const r of rows) {
94	    if (matchesQuery(r, q)) {
95	      const filteredChildren = r.children ? filterRows(r.children, q) : undefined;
96	      out.push({ ...r, children: filteredChildren });
97	    }
98	  }
99	  return out;
100	}
101	
102	export function LeftRail({
103	  sections,
104	  activeRowId,
105	  onRowActivate,
106	  onRowRename,
107	  defaultExpanded,
108	  onRowContextMenu,
109	}: LeftRailProps): JSX.Element {
110	  const { t } = useTranslation();
111	  const [expanded, setExpanded] = useState<Set<string>>(() => new Set(defaultExpanded ?? []));
112	  const [query, setQuery] = useState('');
113	  const [focusedId, setFocusedId] = useState<string | undefined>(activeRowId);
114	
115	  const filteredSections = useMemo(
116	    () =>
117	      query
118	        ? sections
119	            .map((s) => ({ ...s, rows: filterRows(s.rows, query) }))
120	            .filter((s) => s.rows.length > 0)
121	        : sections,
122	    [sections, query],
123	  );
124	
125	  // Auto-expand all rows during search so matches are visible.
126	  const liveExpanded = useMemo(() => {
127	    if (!query) return expanded;
128	    const all = new Set<string>(expanded);
129	    function collect(rows: LeftRailRow[]): void {
130	      for (const r of rows) {
131	        if (r.children?.length) {
132	          all.add(r.id);
133	          collect(r.children);
134	        }
135	      }
136	    }
137	    for (const s of filteredSections) collect(s.rows);
138	    return all;
139	  }, [filteredSections, expanded, query]);
140	
141	  const flat = useMemo(
142	    () => flatten(filteredSections, liveExpanded),
143	    [filteredSections, liveExpanded],
144	  );
145	
146	  const moveFocus = useCallback(
147	    (delta: 1 | -1) => {
148	      if (!flat.length) return;
149	      const idx = focusedId ? flat.findIndex((r) => r.id === focusedId) : -1;
150	      const next = flat[(idx + delta + flat.length) % flat.length];
151	      setFocusedId(next.id);
152	    },
153	    [flat, focusedId],
154	  );
155	
156	  const handleKey = useCallback(
157	    (event: KeyboardEvent<HTMLDivElement>) => {
158	      if (event.key === 'ArrowDown') {
159	        event.preventDefault();
160	        moveFocus(1);
161	      } else if (event.key === 'ArrowUp') {
162	        event.preventDefault();
163	        moveFocus(-1);
164	      } else if (event.key === 'ArrowRight') {
165	        if (!focusedId) return;
166	        event.preventDefault();
167	        setExpanded((prev) => {
168	          const next = new Set(prev);
169	          next.add(focusedId);
170	          return next;
171	        });
172	      } else if (event.key === 'ArrowLeft') {
173	        if (!focusedId) return;
174	        event.preventDefault();
175	        setExpanded((prev) => {
176	          if (!prev.has(focusedId)) return prev;
177	          const next = new Set(prev);
178	          next.delete(focusedId);
179	          return next;
180	        });
181	      } else if (event.key === 'Enter') {
182	        if (!focusedId) return;
183	        event.preventDefault();
184	        onRowActivate?.(focusedId);
185	      } else if (event.key === 'F2') {
186	        if (!focusedId) return;
187	        event.preventDefault();
188	        onRowRename?.(focusedId);
189	      }
190	    },
191	    [focusedId, moveFocus, onRowActivate, onRowRename],
192	  );
193	
194	  return (
195	    <div className="flex h-full flex-col overflow-hidden bg-surface">
196	      <div className="sticky top-0 z-10 border-b border-border bg-surface px-3 py-2">
197	        <SearchField value={query} onChange={setQuery} />
198	      </div>
199	      <div
200	        role="tree"
201	        aria-label={t('workspace.projectBrowser')}
202	        tabIndex={0}
203	        onKeyDown={handleKey}
204	        className="flex-1 overflow-y-auto py-2"
205	      >
206	        {filteredSections.map((s) => (
207	          <SectionBlock key={s.id} section={s}>
208	            {s.rows.map((r) => (
209	              <Row
210	                key={r.id}
211	                row={r}
212	                depth={0}
213	                expanded={liveExpanded}
214	                onToggle={(id) =>
215	                  setExpanded((prev) => {
216	                    const next = new Set(prev);
217	                    if (next.has(id)) next.delete(id);
218	                    else next.add(id);
219	                    return next;
220	                  })
221	                }
222	                onActivate={onRowActivate}
223	                onContextMenu={onRowContextMenu}
224	                activeRowId={activeRowId}
225	                focusedRowId={focusedId}
226	                setFocused={setFocusedId}
227	              />
228	            ))}
229	          </SectionBlock>
230	        ))}
231	        {filteredSections.length === 0 ? (
232	          <div className="px-5 py-3 text-xs text-muted">No matches.</div>
233	        ) : null}
234	      </div>
235	    </div>
236	  );
237	}
