240	export function LeftRailCollapsed({ sections }: { sections: LeftRailSection[] }): JSX.Element {
241	  const { t } = useTranslation();
242	  return (
243	    <nav
244	      aria-label={t('workspace.projectBrowserSections')}
245	      className="flex h-full flex-col items-center gap-2 border-r border-border bg-surface py-3"
246	    >
247	      {sections.map((s) => {
248	        const Icon = s.icon ?? Icons.disclosureClosed;
249	        return (
250	          <button
251	            key={s.id}
252	            type="button"
253	            aria-label={s.label}
254	            title={s.label}
255	            className="inline-flex h-9 w-9 items-center justify-center rounded-md text-foreground hover:bg-surface-strong"
256	          >
257	            <Icon size={ICON_SIZE.toolPalette} aria-hidden="true" />
258	          </button>
259	        );
260	      })}
261	    </nav>
262	  );
263	}
264	
265	function SearchField({
266	  value,
267	  onChange,
268	}: {
269	  value: string;
270	  onChange: (v: string) => void;
271	}): JSX.Element {
272	  const { t } = useTranslation();
273	  return (
274	    <label className="flex items-center gap-2 rounded-md border border-border bg-background px-2 py-1.5 text-sm focus-within:ring-2 focus-within:ring-offset-0">
275	      <Icons.search size={ICON_SIZE.chrome} className="text-muted" aria-hidden="true" />
276	      <input
277	        type="search"
278	        placeholder={t('workspace.searchProject')}
279	        aria-label={IconLabels.search}
280	        value={value}
281	        onChange={(e) => onChange(e.target.value)}
282	        className="flex-1 bg-transparent text-sm text-foreground outline-none placeholder:text-muted"
283	      />
284	    </label>
285	  );
286	}
287	
288	function SectionBlock({
289	  section,
290	  children,
291	}: {
292	  section: LeftRailSection;
293	  children: ReactNode;
294	}): JSX.Element {
295	  return (
296	    <div className="mb-2">
297	      <div
298	        className="flex items-center gap-1.5 px-5 py-1 text-xs uppercase text-muted"
299	        style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
300	      >
301	        {section.icon ? <section.icon size={12} aria-hidden="true" /> : null}
302	        <span>{section.label}</span>
303	      </div>
304	      {children}
305	    </div>
306	  );
307	}
308	
309	interface RowProps {
310	  row: LeftRailRow;
311	  depth: number;
312	  expanded: ReadonlySet<string>;
313	  onToggle: (id: string) => void;
314	  onActivate?: (id: string) => void;
315	  onContextMenu?: (id: string, event: { x: number; y: number }) => void;
316	  activeRowId?: string;
317	  focusedRowId?: string;
318	  setFocused: (id: string) => void;
319	}
320	
321	function Row({
322	  row,
323	  depth,
324	  expanded,
325	  onToggle,
326	  onActivate,
327	  onContextMenu,
328	  activeRowId,
329	  focusedRowId,
330	  setFocused,
331	}: RowProps): JSX.Element {
332	  const hasChildren = !!row.children?.length;
333	  const isOpen = expanded.has(row.id);
334	  const isActive = row.id === activeRowId;
335	  const isFocused = row.id === focusedRowId;
336	  const ref = useRef<HTMLButtonElement | null>(null);
337	
338	  useEffect(() => {
339	    if (isFocused) ref.current?.focus({ preventScroll: true });
340	  }, [isFocused]);
341	
342	  const indentStyle: CSSProperties = {
343	    paddingLeft: `calc(var(--space-5) + ${depth} * var(--space-5))`,
344	  };
345	
346	  return (
347	    <div role="none">
348	      <button
349	        ref={ref}
350	        type="button"
351	        role="treeitem"
352	        aria-level={depth + 1}
353	        aria-expanded={hasChildren ? isOpen : undefined}
354	        aria-selected={isActive}
355	        tabIndex={isFocused ? 0 : -1}
356	        onClick={() => {
357	          setFocused(row.id);
358	          if (hasChildren) onToggle(row.id);
359	          onActivate?.(row.id);
360	        }}
361	        onContextMenu={(event) => {
362	          if (!onContextMenu) return;
363	          event.preventDefault();
364	          onContextMenu(row.id, { x: event.clientX, y: event.clientY });
365	        }}
366	        data-testid={`left-rail-row-${row.id}`}
367	        data-active={isActive ? 'true' : 'false'}
368	        style={indentStyle}
369	        className={[
370	          'flex h-7 w-full items-center gap-1.5 pr-3 text-sm',
371	          isActive ? 'bg-accent-soft text-foreground' : 'text-foreground hover:bg-surface-strong',
372	        ].join(' ')}
373	      >
374	        <span className="inline-flex w-4 items-center justify-center">
375	          {hasChildren ? (
376	            isOpen ? (
377	              <Icons.disclosureOpen size={12} aria-hidden="true" />
378	            ) : (
379	              <Icons.disclosureClosed size={12} aria-hidden="true" />
380	            )
381	          ) : null}
382	        </span>
383	        {row.icon ? <row.icon size={12} aria-hidden="true" className="text-muted" /> : null}
384	        <span className="truncate">{row.label}</span>
385	        {row.hint ? <span className="ml-auto truncate text-xs text-muted">{row.hint}</span> : null}
386	      </button>
387	      {hasChildren && isOpen
388	        ? (row.children ?? []).map((c) => (
389	            <Row
390	              key={c.id}
391	              row={c}
392	              depth={depth + 1}
393	              expanded={expanded}
394	              onToggle={onToggle}
395	              onActivate={onActivate}
396	              onContextMenu={onContextMenu}
397	              activeRowId={activeRowId}
398	              focusedRowId={focusedRowId}
399	              setFocused={setFocused}
400	            />
401	          ))
402	        : null}
403	    </div>
404	  );
405	}
