      if (el.kind === 'viewpoint') {
        openTabFromElement(el);
        handleModeChange('3d');
        select(id);
        return;
      }
      if (el.kind === 'section_cut') {
        openTabFromElement(el);
        handleModeChange('section');
        select(id);
        return;
      }
      if (el.kind === 'sheet') {
        openTabFromElement(el);
        handleModeChange('sheet');
        select(id);
        return;
      }
      if (el.kind === 'schedule') {
        openTabFromElement(el);
        handleModeChange('schedule');
        select(id);
        return;
      }
      select(id);
    }}
